// 115 quiz questions + 67 study flashcards + 15 comparison drills

export const STUDY_CARDS = [
  // ── GRAPE VARIETIES ────────────────────────
  {cat:0, front:"Chardonnay — Key facts", back:"World's most popular white grape. Burgundy & Champagne homeland. Styles range from lean/mineral (Chablis, unoaked) to rich/buttery (oaked, MLF). Aromas: green apple, citrus → tropical fruit in warm climates. Takes well to oak (vanilla, toast) and lees ageing.",
    quiz:{q:"What gives oaked Chardonnay its buttery, creamy character?",o:["Botrytis","Malolactic fermentation (MLF)","Carbonic maceration","High residual sugar"],a:1}},
  {cat:0, front:"Sauvignon Blanc — Key facts", back:"High acidity, aromatic. Green fruit (gooseberry, green apple), herbaceous (cut grass, asparagus). Key regions: Loire Valley (Sancerre, Pouilly-Fumé), Marlborough NZ (intense passion fruit), Bordeaux (blended with Sémillon). Usually unoaked to preserve freshness.",
    quiz:{q:"What are the TWO key regions for Sauvignon Blanc?",o:["Burgundy & Barossa","Loire Valley & Marlborough NZ","Piedmont & Napa","Alsace & Margaret River"],a:1}},
  {cat:0, front:"Pinot Noir — Key facts", back:"Thin-skinned, difficult to grow. Pale to medium ruby colour. Red fruit: cherry, strawberry, raspberry. Light-medium tannin, high acidity. Best in cool climates: Burgundy (benchmark), Oregon, NZ Central Otago. Ages to earthy, mushroom, forest floor.",
    quiz:{q:"Pinot Noir is best known for which colour and tannin level?",o:["Deep colour, high tannin","Pale-medium ruby, light-medium tannin","Very dark, no tannin","Variable colour, very high tannin"],a:1}},
  {cat:0, front:"Cabernet Sauvignon — Key facts", back:"World's most planted red grape. Thick-skinned → deep colour, high tannin. Blackcurrant (cassis), black cherry. Ages well: develops cedar, tobacco, cigar box. Key: Bordeaux Left Bank (with Merlot), Napa Valley, Coonawarra. Full body, high acidity.",
    quiz:{q:"Cabernet Sauvignon's signature aroma is:",o:["Cherry and strawberry","Blackcurrant (cassis)","Lychee and rose petal","Green apple and citrus"],a:1}},
  {cat:0, front:"Merlot — Key facts", back:"Softer and more approachable than Cabernet Sauvignon. Plum, red fruit, medium tannin. Key: Bordeaux Right Bank (Saint-Émilion, Pomerol). Often blended with Cabernet Sauvignon. Early-drinking but top examples age well. Moderate acidity.",
    quiz:{q:"Merlot dominates which side of Bordeaux?",o:["Left Bank","Right Bank","Both equally","Neither — it's a Burgundy grape"],a:1}},
  {cat:0, front:"Syrah / Shiraz — Key facts", back:"Same grape, two names. SYRAH (France/cool): black pepper, violet, black olive, elegant. Northern Rhône: Hermitage, Côte-Rôtie. SHIRAZ (Australia/warm): ripe blackberry, chocolate, liquorice, fuller. Barossa Valley benchmark. High tannin, deep colour.",
    quiz:{q:"In France it's called Syrah. In Australia it's called:",o:["Grenache","Shiraz","Tempranillo","Pinotage"],a:1}},
  {cat:0, front:"Riesling — Key facts", back:"Highly aromatic, high acidity. Germany's star (Mosel, Rheingau, Pfalz). Also Alsace. Styles: bone dry to lusciously sweet. Aromas: lime, green apple, floral → petrol/kerosene with age. Light body, low-medium alcohol. Excellent ageing potential.",
    quiz:{q:"What distinctive aroma does Riesling develop with age?",o:["Vanilla and toast","Petrol/kerosene","Blackcurrant","Lychee"],a:1}},
  {cat:0, front:"Chenin Blanc — Key facts", back:"Loire Valley star: Vouvray, Savennières. Incredibly versatile: dry, off-dry, sweet, sparkling. High acidity. Aromas: apple, pear, honey, quince. Susceptible to noble rot → great sweet wines. Also major in South Africa (called Steen).",
    quiz:{q:"In South Africa, Chenin Blanc is known as:",o:["Pinotage","Steen","Colombard","Cinsaut"],a:1}},
  {cat:0, front:"Grenache / Garnacha — Key facts", back:"Warm-climate grape. Southern Rhône dominant (Châteauneuf-du-Pape — up to 13 varieties allowed). Also Spain (Garnacha). Red fruit, spice, high alcohol, low-medium tannin. Often blended: GSM (Grenache-Syrah-Mourvèdre).",
    quiz:{q:"How many grape varieties are allowed in Châteauneuf-du-Pape?",o:["3","5","Up to 13","Only 1 (Grenache)"],a:2}},
  {cat:0, front:"Nebbiolo — Key facts", back:"Piedmont, Italy only. Barolo and Barbaresco. Very high tannin, very high acidity, pale colour (deceptive). Aromas: tar, roses, cherry, dried herbs. Needs long ageing. 'The fog grape' (nebbia = fog). One of Italy's greatest grapes.",
    quiz:{q:"Nebbiolo's colour is deceptive because it is:",o:["Very deep despite low tannin","Pale despite very high tannin","Always brown","Identical to Merlot"],a:1}},
  {cat:0, front:"Sangiovese — Key facts", back:"Tuscany's grape. Chianti, Brunello di Montalcino, Vino Nobile. Cherry fruit, dried herbs, high acidity, firm tannins. Medium-deep colour. Often blended in Chianti (with Merlot, Cab Sauv). Sensitive to terroir.",
    quiz:{q:"Sangiovese is the principal grape of:",o:["Barolo","Chianti","Rioja","Beaujolais"],a:1}},
  {cat:0, front:"Tempranillo — Key facts", back:"Spain's noble red. Rioja (main grape), Ribera del Duero (called Tinto Fino). Cherry, plum, leather, tobacco. Medium-full body, moderate tannin. Takes well to oak ageing. Name means 'early' — ripens early for Spain.",
    quiz:{q:"What does 'Tempranillo' mean?",o:["Noble","Dark","Early (ripening)","Powerful"],a:2}},
  {cat:0, front:"Gewürztraminer — Key facts", back:"Highly aromatic, low acidity. Lychee, rose petal, Turkish delight. Deep golden colour. Alsace is the benchmark. Full-bodied for a white. Often off-dry. Gewürz = spice in German.",
    quiz:{q:"Gewürztraminer's signature aromas are:",o:["Green apple and grass","Lychee and rose petal","Blackcurrant and cedar","Citrus and flint"],a:1}},
  {cat:0, front:"Malbec — Key facts", back:"Originally from Cahors, France (called Côt). Found greatest success in Mendoza, Argentina. Deep, inky colour. Plum, blackberry, violet, chocolate. Full body, soft tannins. High altitude vineyards in Argentina.",
    quiz:{q:"Malbec's French origin is:",o:["Bordeaux","Burgundy","Cahors","Alsace"],a:2}},
  {cat:0, front:"Pinot Gris / Pinot Grigio", back:"Same grape, different styles. PINOT GRIGIO (Italy): light, crisp, neutral, high-volume. PINOT GRIS (Alsace): richer, fuller, aromatic, stone fruit, spice. Also NZ (between the two styles). Grey-pink skin.",
    quiz:{q:"Which style is richer — Italian Pinot Grigio or Alsatian Pinot Gris?",o:["Italian Pinot Grigio","Alsatian Pinot Gris","They're identical","Neither — both are always light"],a:1}},
  {cat:0, front:"Gamay — Key facts", back:"Beaujolais only significant region. Light body, low tannin, high acidity. Red fruit: cherry, raspberry. Often made by carbonic maceration (Beaujolais Nouveau). Cru Beaujolais (Morgon, Fleurie, Moulin-à-Vent) can be more serious.",
    quiz:{q:"Which winemaking technique is classic for Beaujolais Nouveau?",o:["Extended maceration","Carbonic maceration","Malolactic fermentation","Bâtonnage"],a:1}},
  {cat:0, front:"Sémillon — Key facts", back:"Bordeaux blending partner with Sauvignon Blanc. Thin-skinned → susceptible to botrytis (noble rot). Key for Sauternes sweet wine. Also Hunter Valley, Australia (ages to toast/honey). Low acidity, waxy texture, full body.",
    quiz:{q:"Sémillon is crucial for which famous sweet wine?",o:["Tokaji Aszú","Asti","Sauternes","Eiswein"],a:2}},
  {cat:0, front:"Viognier — Key facts", back:"Aromatic white. Peach, apricot, blossom. Full body, low acidity. Northern Rhône: Condrieu (benchmark). Sometimes co-fermented with Syrah in Côte-Rôtie. Rich, oily texture.",
    quiz:{q:"Viognier's benchmark appellation is:",o:["Chablis","Sancerre","Condrieu","Vouvray"],a:2}},
  {cat:0, front:"Muscat — Key facts", back:"One of the few grapes that actually smells grapey. Many styles: dry (Alsace), sweet (Muscat de Beaumes-de-Venise), sparkling (Asti, Moscato d'Asti). Floral, grape, orange blossom. Note: Muscadet is NOT Muscat — it's Melon de Bourgogne.",
    quiz:{q:"Muscat is unique because its wine:",o:["Is always red","Actually smells and tastes of grapes","Can only be sparkling","Has no aroma"],a:1}},

  // ── REGIONS & COUNTRIES ────────────────────
  {cat:1, front:"Bordeaux — The essentials", back:"Left Bank: Cabernet Sauvignon dominant (Médoc, Pauillac, Margaux, Saint-Julien, Saint-Estèphe, Graves/Pessac-Léognan). Right Bank: Merlot dominant (Saint-Émilion, Pomerol). White: Sauvignon Blanc + Sémillon. Sweet: Sauternes. Maritime climate.",
    quiz:{q:"Which grape dominates Bordeaux's Left Bank?",o:["Merlot","Pinot Noir","Cabernet Sauvignon","Syrah"],a:2}},
  {cat:1, front:"Burgundy — The essentials", back:"Pinot Noir (red) and Chardonnay (white) only. Quality pyramid: Regional → Village → Premier Cru → Grand Cru. Key areas: Chablis (north, lean Chardonnay), Côte d'Or = Côte de Nuits (reds) + Côte de Beaune (whites). Continental climate.",
    quiz:{q:"What is the highest quality level in Burgundy?",o:["Village","Premier Cru","Grand Cru","Réserve"],a:2}},
  {cat:1, front:"Loire Valley — The essentials", back:"France's garden. Muscadet (Melon de Bourgogne, light, sur lie). Sancerre & Pouilly-Fumé (Sauvignon Blanc). Vouvray (Chenin Blanc — dry to sweet). Chinon & Bourgueil (Cabernet Franc). Crémant de Loire (sparkling). Cool maritime/continental climate.",
    quiz:{q:"Vouvray is made from which grape?",o:["Sauvignon Blanc","Melon de Bourgogne","Chenin Blanc","Chardonnay"],a:2}},
  {cat:1, front:"Rhône Valley — North vs South", back:"NORTH: Syrah only red. Hermitage, Côte-Rôtie, Cornas. Viognier (Condrieu). Continental. SOUTH: Grenache dominant, blends. Châteauneuf-du-Pape (up to 13 varieties). Côtes du Rhône (everyday). Mediterranean, warm.",
    quiz:{q:"The Northern Rhône's ONLY red grape is:",o:["Grenache","Mourvèdre","Syrah","Cabernet Franc"],a:2}},
  {cat:1, front:"Germany — The essentials", back:"Riesling king. Mosel (steep slate slopes, light, off-dry). Rheingau (fuller). Pfalz (warmer). Prädikat system by ripeness: Kabinett → Spätlese → Auslese → Beerenauslese → Trockenbeerenauslese. Trocken = dry.",
    quiz:{q:"The German Prädikat system classifies wines by:",o:["Vineyard prestige","Grape ripeness at harvest","Years of ageing","Alcohol content"],a:1}},
  {cat:1, front:"Italy — The essentials", back:"Piedmont: Nebbiolo (Barolo, Barbaresco), Barbera, Moscato d'Asti. Tuscany: Sangiovese (Chianti, Brunello). Veneto: Prosecco (Glera), Valpolicella, Amarone. Quality: Vino → IGT → DOC → DOCG (highest).",
    quiz:{q:"Italy's HIGHEST quality classification is:",o:["DOC","IGT","DOCG","Vino"],a:2}},
  {cat:1, front:"Spain — The essentials", back:"Rioja: Tempranillo, oak-aged (Crianza/Reserva/Gran Reserva). Ribera del Duero: Tempranillo (Tinto Fino). Rías Baixas: Albariño. Priorat: Garnacha, old vines. Sherry: Jerez. Cava: traditional method sparkling.",
    quiz:{q:"Gran Reserva requires the LONGEST ageing. What comes just before it?",o:["Crianza","Joven","Reserva","Roble"],a:2}},
  {cat:1, front:"Australia — Key regions", back:"Barossa Valley: old-vine Shiraz, powerful. Clare & Eden Valley: dry Riesling. McLaren Vale: Shiraz, Grenache. Margaret River (WA): Cabernet, Chardonnay. Yarra Valley (VIC): Pinot Noir. Warm to hot, mostly.",
    quiz:{q:"Clare Valley and Eden Valley are best known for:",o:["Shiraz","Chardonnay","Riesling","Cabernet Sauvignon"],a:2}},
  {cat:1, front:"New Zealand — Key regions", back:"Marlborough: Sauvignon Blanc (benchmark — intense, passion fruit, herbaceous). Central Otago: Pinot Noir (world's most southerly). Hawke's Bay: Bordeaux-style reds. Cool maritime climate.",
    quiz:{q:"Central Otago is famous for which grape?",o:["Sauvignon Blanc","Chardonnay","Pinot Noir","Syrah"],a:2}},
  {cat:1, front:"Argentina & Chile", back:"ARGENTINA: Mendoza = Malbec (high altitude, Andes foothills). Deep colour, plummy, soft tannin. CHILE: Maipo Valley (Cabernet Sauvignon), Casablanca (cool, white), Carménère (signature grape, ex-Bordeaux). Andes protection.",
    quiz:{q:"Chile's signature grape, originally from Bordeaux, is:",o:["Malbec","Tannat","Carménère","Tempranillo"],a:2}},
  {cat:1, front:"South Africa — Key facts", back:"Stellenbosch: premium Cabernet, Bordeaux blends. Chenin Blanc (called Steen) most planted white. Pinotage (Pinot Noir × Cinsaut cross, unique to SA). Constantia: historic sweet wines. Warm Mediterranean climate.",
    quiz:{q:"Pinotage is a cross of which two grapes?",o:["Cabernet × Merlot","Pinot Noir × Cinsaut","Syrah × Grenache","Chardonnay × Riesling"],a:1}},
  {cat:1, front:"USA — Key regions", back:"Napa Valley: Cabernet Sauvignon (world-class, premium). Sonoma: diverse — Pinot Noir, Chardonnay, Zinfandel. Oregon Willamette Valley: Pinot Noir (Burgundy-like cool climate). Washington: Merlot, Syrah (continental).",
    quiz:{q:"Oregon's Willamette Valley is most celebrated for:",o:["Cabernet Sauvignon","Zinfandel","Pinot Noir","Riesling"],a:2}},
  {cat:1, front:"Alsace — Key facts", back:"Northeast France, German border. Rain shadow of Vosges mountains → dry, sunny. Riesling, Gewürztraminer, Pinot Gris, Muscat. Varietal labelling (unusual for France). Grand Cru vineyards. Dry to sweet styles.",
    quiz:{q:"Alsace is unusual for France because its labels show:",o:["Only the region name","The grape variety","Only the vintage","The producer's coat of arms"],a:1}},

  // ── WINEMAKING ─────────────────────────────
  {cat:2, front:"Fermentation — The basics", back:"Alcoholic fermentation: yeast converts sugar → alcohol + CO₂. Happens in stainless steel (preserves fruit), oak barrels (adds flavour), or concrete. Temperature control is key: cool = aromatic preservation, warm = more extraction.",
    quiz:{q:"Alcoholic fermentation converts sugar into:",o:["Acid + tannin","Alcohol + CO₂","Water + alcohol","Sugar + oxygen"],a:1}},
  {cat:2, front:"Malolactic Fermentation (MLF)", back:"Converts sharp malic acid (green apple) → softer lactic acid (dairy/cream). Makes wine smoother and rounder. Standard for most reds. Optional for whites — used in oaked Chardonnay, avoided in crisp Sauvignon Blanc/Riesling.",
    quiz:{q:"MLF converts malic acid into:",o:["Citric acid","Tartaric acid","Lactic acid","Acetic acid"],a:2}},
  {cat:2, front:"Oak — Effects on wine", back:"New oak adds: vanilla, toast, clove, coconut, smoke, spice, plus tannin. Old oak (3-4 uses): mostly neutral, allows gentle oxidation. French oak: finer, subtle. American oak: more obvious coconut/dill. Small barrels = more contact.",
    quiz:{q:"After how many uses does oak become largely neutral?",o:["1 use","2 uses","3-4 uses","10+ uses"],a:2}},
  {cat:2, front:"Lees ageing & bâtonnage", back:"Lees = dead yeast cells after fermentation. Ageing on lees adds: richness, creaminess, bready/biscuity notes. Bâtonnage = stirring lees during ageing for more contact. Used in: Champagne, Muscadet sur lie, oaked Chardonnay.",
    quiz:{q:"Bâtonnage means:",o:["Pressing the grapes","Stirring the lees","Adding sulphites","Filtering the wine"],a:1}},
  {cat:2, front:"Climate effects on wine", back:"COOL climate: higher acidity, lower sugar → lower alcohol, more subtle fruit, greener notes. WARM climate: lower acidity, higher sugar → higher alcohol, riper/tropical fruit, softer. Climate is the #1 factor in wine style.",
    quiz:{q:"A cool climate typically produces wines with:",o:["High sugar, low acidity","Low sugar, high acidity","High sugar, high acidity","No effect on either"],a:1}},
  {cat:2, front:"Red vs White winemaking", back:"KEY DIFFERENCE: Red wines ferment WITH skins (maceration) → colour, tannin, body. White wines: press first, ferment juice only. Longer skin contact = deeper colour, more tannin. Rosé: short skin contact (hours, not days).",
    quiz:{q:"Red wine gets its colour from:",o:["The juice itself","Skin contact during fermentation","Added colourants","The type of yeast"],a:1}},
  {cat:2, front:"Carbonic maceration", back:"Whole bunches of uncrushed grapes placed in sealed vat filled with CO₂. Fermentation happens inside the grape. Result: very fruity, low tannin, bright colour. Classic: Beaujolais Nouveau. Light, juicy, drink young.",
    quiz:{q:"In carbonic maceration, grapes go into the vat:",o:["Fully crushed","Partially crushed","Whole and uncrushed","As juice only"],a:2}},
  {cat:2, front:"Chaptalisation", back:"Adding sugar to grape must BEFORE fermentation to increase alcohol (not sweetness — sugar converts fully to alcohol). Used in cool regions (Burgundy) where grapes may not ripen fully. Banned in many warm regions (Australia, southern France).",
    quiz:{q:"Chaptalisation adds sugar to increase:",o:["Sweetness","Acidity","Alcohol","Colour"],a:2}},
  {cat:2, front:"Fining & filtering", back:"Fining: adding agents (egg white, bentonite clay, casein) to attract and remove unwanted particles → clearer wine. Filtering: passing wine through a filter. Some winemakers skip both ('unfined, unfiltered') for more character.",
    quiz:{q:"The purpose of fining is to:",o:["Add flavour","Increase alcohol","Clarify and stabilise the wine","Add colour"],a:2}},
  {cat:2, front:"Sulphur dioxide (SO₂)", back:"Added to wine as preservative and antioxidant. Prevents oxidation and microbial spoilage. Almost ALL wines contain some. 'Contains sulphites' on label is legally required. Levels: lower in reds, higher in sweet whites. Natural wines use minimal/none.",
    quiz:{q:"SO₂ in winemaking acts as a:",o:["Sweetener","Preservative and antioxidant","Colourant","Fermenting agent"],a:1}},
  {cat:2, front:"Noble rot (Botrytis cinerea)", back:"A beneficial fungus that shrivels grapes → concentrates sugar, acidity, flavour. Needs specific conditions: morning mist + afternoon sun. Produces: Sauternes (Bordeaux), Tokaji Aszú (Hungary), TBA wines (Germany), Loire sweet wines. Expensive (low yields, hand-picking).",
    quiz:{q:"Noble rot CONCENTRATES what in the grape?",o:["Alcohol","Tannin","Sugar, acidity, and flavour","Colour pigments"],a:2}},
  {cat:2, front:"Vintage year & vintage variation", back:"Vintage = year grapes were harvested. Weather varies year to year → different quality/style each vintage. More important in marginal climates (Bordeaux, Burgundy) than reliable ones (Barossa). NV Champagne blends years for consistency.",
    quiz:{q:"Vintage variation matters MORE in:",o:["Warm, reliable climates (Barossa)","Cool, marginal climates (Bordeaux)","Only in the Southern Hemisphere","It doesn't matter anywhere"],a:1}},

  // ── WINE STYLES & LABELS ───────────────────
  {cat:3, front:"French classification: AOC/AOP", back:"Appellation d'Origine Contrôlée / Protégée. France's top quality level. Strict rules: permitted grapes, yields, methods, geographic origin. Examples: Chablis, Sancerre, Châteauneuf-du-Pape. Below: IGP (regional), Vin de France (basic).",
    quiz:{q:"What is the level BELOW AOC/AOP in France?",o:["DOCG","IGP","Grand Cru","Vin de Table"],a:1}},
  {cat:3, front:"Italian classification: DOC & DOCG", back:"DOC = Denominazione di Origine Controllata (controlled). DOCG = adds 'Garantita' (guaranteed) — highest level, requires tasting panel. Below: IGT (flexible, can be excellent), Vino. DOCG examples: Barolo, Chianti Classico, Brunello.",
    quiz:{q:"What does the 'G' in DOCG stand for?",o:["Grande","Garantita (Guaranteed)","Generale","Governo"],a:1}},
  {cat:3, front:"Spanish ageing terms", back:"Crianza: 2 years total, 6 months oak (reds). Reserva: 3 years total, 12 months oak. Gran Reserva: 5 years total, 18 months oak. Only made in good vintages. Applies to Rioja, Ribera del Duero, others.",
    quiz:{q:"Crianza reds require a minimum of how many months in oak?",o:["3 months","6 months","12 months","18 months"],a:1}},
  {cat:3, front:"German Prädikat system", back:"Classified by grape RIPENESS at harvest (not vineyard quality). Ascending sweetness potential: Kabinett → Spätlese → Auslese → Beerenauslese (BA) → Trockenbeerenauslese (TBA) → Eiswein. 'Trocken' on label = dry. Can be any style within these.",
    quiz:{q:"'Trocken' on a German wine label means:",o:["Sweet","Off-dry","Dry","Sparkling"],a:2}},
  {cat:3, front:"Sweetness levels in wine", back:"Dry: <4 g/l residual sugar. Off-dry: 4-12 g/l. Medium: 12-45 g/l. Sweet: >45 g/l. Perception affected by acidity — high acid makes wine taste drier. Sparkling: Brut Nature (0-3) → Extra Brut → Brut (<12) → Extra Dry (12-17) → Demi-Sec → Doux.",
    quiz:{q:"'Extra Dry' on a Prosecco label is actually:",o:["Bone dry","Slightly sweeter than Brut","The driest possible","The same as Brut"],a:1}},
  {cat:3, front:"Old World vs New World", back:"OLD WORLD: Europe, Middle East. Labels by REGION (Chablis, Chianti). Tradition, terroir-focused. NEW WORLD: Americas, Australasia, South Africa. Labels by GRAPE (Chardonnay, Shiraz). Innovation, fruit-forward. Lines are blurring.",
    quiz:{q:"Old World wines typically label by:",o:["Grape variety","Region/appellation","Winemaker name","Alcohol level"],a:1}},
  {cat:3, front:"Reading a wine label", back:"Key info: Producer name, Region/appellation, Vintage year, Grape variety (if stated), Alcohol % (ABV), Volume, Quality classification (AOC, DOC, etc.). 'Estate bottled' / 'Mis en bouteille au château' = made & bottled at the property.",
    quiz:{q:"'Mis en bouteille au château' means:",o:["Made by a cooperative","Bottled at the estate","Aged in oak","A blend of vintages"],a:1}},
  {cat:3, front:"Body, acidity, tannin", back:"BODY: overall weight/richness (light/medium/full). Affected by alcohol, sugar, extract. ACIDITY: freshness, crispness (makes mouth water). TANNIN: drying/gripping sensation (reds mainly, from skins/seeds/oak). These 3 are key tasting descriptors.",
    quiz:{q:"Tannin creates which sensation in the mouth?",o:["Sweetness","Mouth-watering freshness","Drying/gripping sensation","Fizzing/tingling"],a:2}},

  // ── SPARKLING & FORTIFIED ──────────────────
  {cat:4, front:"Traditional Method sparkling", back:"Second fermentation IN THE BOTTLE. Steps: base wine → add yeast+sugar → seal → ferment → lees ageing (months to years) → riddling (remuage) → disgorgement (dégorgement) → dosage (sweetness). Used: Champagne, Cava, Crémant, top NW sparkling. Fine bubbles, biscuity complexity.",
    quiz:{q:"In the Traditional Method, the second fermentation happens:",o:["In a large tank","In the bottle","In an oak barrel","In a concrete egg"],a:1}},
  {cat:4, front:"Tank Method (Charmat)", back:"Second fermentation in large PRESSURISED TANK. Faster, cheaper than Traditional Method. Preserves fresh, fruity, floral character. Used: Prosecco (Glera grape), Asti. Less yeasty complexity, larger bubbles. Great for aromatic grapes.",
    quiz:{q:"Which wine is the classic example of the Tank Method?",o:["Champagne","Cava","Prosecco","Crémant"],a:2}},
  {cat:4, front:"Champagne — Key facts", back:"Only from Champagne region, NE France. Traditional Method only. Grapes: Chardonnay, Pinot Noir, Pinot Meunier. Blanc de Blancs = 100% Chardonnay. Blanc de Noirs = Pinot Noir/Meunier. NV = multi-vintage blend. Vintage = single exceptional year.",
    quiz:{q:"Blanc de Blancs Champagne is made from:",o:["Pinot Noir only","All three grapes","Chardonnay only","Pinot Meunier only"],a:2}},
  {cat:4, front:"Sparkling sweetness scale", back:"Driest → sweetest: Brut Nature (0-3 g/l) → Extra Brut (0-6) → BRUT (<12, most common) → Extra Dry (12-17, confusingly sweeter than Brut!) → Dry/Sec (17-32) → Demi-Sec (32-50) → Doux (>50). Exam loves the Extra Dry trick!",
    quiz:{q:"Which is DRIER — Brut or Extra Dry?",o:["Extra Dry is drier","Brut is drier","They're identical","It depends on the producer"],a:1}},
  {cat:4, front:"Port — Key facts", back:"Douro Valley, Portugal. Fortified DURING fermentation (spirit kills yeast → retains sweetness). 19-22% ABV. RUBY: aged in large vessels, red fruit, fresh. TAWNY: aged in small barrels, amber, nutty, caramel. LBV: single vintage, 4-6 years. Vintage: top quality, decades of ageing.",
    quiz:{q:"Port is fortified at which stage?",o:["Before fermentation","During fermentation","After fermentation is complete","At bottling"],a:1}},
  {cat:4, front:"Sherry — Key facts", back:"Jerez, southern Spain. Palomino grape (dry styles). FINO: aged under flor (yeast layer), light, dry, nutty, delicate. MANZANILLA: Fino from Sanlúcar, even lighter. OLOROSO: no flor, oxidative ageing, dark, rich, nutty, dry. Cream Sherry = sweetened Oloroso. AMONTILLADO: starts as Fino, loses flor, then oxidative.",
    quiz:{q:"'Flor' in Sherry production is:",o:["A grape variety","A layer of yeast on the wine's surface","A type of barrel","A blending technique"],a:1}},
  {cat:4, front:"Sauternes & sweet wines", back:"Sauternes: Bordeaux. Sémillon + Sauvignon Blanc + botrytis. Luscious, honeyed, apricot, marmalade. Château d'Yquem = most famous. Other sweet wines: Tokaji Aszú (Hungary, Furmint), German BA/TBA/Eiswein, Loire Coteaux du Layon (Chenin Blanc).",
    quiz:{q:"Tokaji Aszú is made from which grape?",o:["Sémillon","Riesling","Furmint","Muscat"],a:2}},
  {cat:4, front:"Cava & Prosecco compared", back:"CAVA: Spain, Traditional Method, Macabeo/Parellada/Xarel-lo, more yeasty/complex. PROSECCO: Italy, Tank Method, Glera grape, fresher/fruitier. Both good value alternatives to Champagne. Prosecco: Brut most popular. Cava: longer lees ageing possible.",
    quiz:{q:"Cava's three main grapes are:",o:["Chardonnay, Pinot Noir, Meunier","Macabeo, Parellada, Xarel-lo","Glera, Trebbiano, Garganega","Tempranillo, Garnacha, Monastrell"],a:1}},

  // ── FOOD & WINE PAIRING ────────────────────
  {cat:5, front:"The golden rule of pairing", back:"Match WEIGHT and INTENSITY. Light food → light wine. Rich food → full-bodied wine. Don't overpower delicate food with heavy wine, and don't lose big wine next to plain food. Think of it like volume matching.",
    quiz:{q:"The #1 rule of food and wine pairing is to match:",o:["Colour of food and wine","Price of food and wine","Weight and intensity","Sweetness levels only"],a:2}},
  {cat:5, front:"Acidity in pairing", back:"High-acid wine + fatty/rich food = PERFECT. Acid cuts through richness like a squeeze of lemon. Examples: Champagne + fried food, Chianti + rich tomato pasta, Sauvignon Blanc + goat cheese. Acidic food needs acidic wine (or wine tastes flat).",
    quiz:{q:"High-acid wine is best paired with:",o:["Very sweet desserts","Fatty, rich, or oily foods","Bitter salads","Plain steamed rice"],a:1}},
  {cat:5, front:"Tannin in pairing", back:"Tannin + PROTEIN = great (protein softens tannin). Red meat, hard cheese with tannic reds. Tannin + salt = good (salt reduces bitterness). Tannin + oily fish = BAD (metallic taste). Tannin + spicy food = BAD (amplifies heat).",
    quiz:{q:"Protein in food does what to tannin?",o:["Amplifies it","Softens it","Has no effect","Removes it entirely"],a:1}},
  {cat:5, front:"Sweetness in pairing", back:"CRITICAL RULE: wine must be at least as sweet as the food. Sweet food + dry wine = wine tastes bitter, thin, acidic. Sweet food + sweet wine = harmony. Classic: Sauternes + foie gras, Port + Stilton, Muscat + fruit dessert.",
    quiz:{q:"If dessert is sweeter than the wine, the wine will taste:",o:["Sweeter","Bitter, thin, and acidic","The same","More fruity"],a:1}},
  {cat:5, front:"Salt, umami & spice", back:"SALT: softens tannin, makes wine fruitier (great with tannic reds). UMAMI (parmesan, soy): makes wine more bitter/astringent — avoid big tannic wines, choose fruity/off-dry. CHILLI SPICE: amplified by alcohol and tannin. Choose low-alcohol, off-dry (German Riesling Spätlese).",
    quiz:{q:"Chilli-spicy food is WORST paired with:",o:["Low alcohol, off-dry wines","High alcohol, tannic wines","Sparkling wines","Rosé wines"],a:1}},
  {cat:5, front:"Regional pairing principle", back:"'What grows together goes together.' Centuries of co-evolution: Chianti (high acid Sangiovese) + tomato-based Tuscan food. Sancerre (Sauvignon Blanc) + Loire goat cheese. Rioja + Spanish lamb. Muscadet + Atlantic oysters.",
    quiz:{q:"Sancerre pairs classically with Loire goat cheese because:",o:["Both are expensive","Both evolved in the same region over centuries","Both are sweet","The cheese is tannic"],a:1}},
  {cat:5, front:"Classic pairings to memorise", back:"Champagne + fried food/oysters. Sancerre + goat cheese. Chianti + tomato pasta. Cab Sauv + grilled steak. Pinot Noir/rosé + salmon. Riesling Spätlese + spicy Thai. Sauternes + foie gras or blue cheese. Port + Stilton. Muscat + fruit tart.",
    quiz:{q:"Which wine is the classic pairing for Stilton blue cheese?",o:["Dry Sauvignon Blanc","Port","Light Pinot Grigio","Dry Fino Sherry"],a:1}},
];

