export const QUESTIONS = [
  {id:1,cat:0,d:1,q:"Which grape variety is most associated with the Burgundy region of France?",o:["Chardonnay & Pinot Noir","Cabernet Sauvignon & Merlot","Syrah & Viognier","Riesling & Gewürztraminer"],a:0,exp:"Burgundy is famous for Chardonnay (white) and Pinot Noir (red). These are the only permitted grape varieties for top Burgundy wines."},
  {id:2,cat:0,d:1,q:"Sauvignon Blanc is known for which primary aroma characteristic?",o:["Tropical fruit and oak","Green fruit, herbaceous (gooseberry, cut grass)","Stone fruit and honey","Floral and lychee"],a:1,exp:"Sauvignon Blanc is typically characterised by green fruit (gooseberry, green apple), herbaceous notes (cut grass, asparagus), and high acidity."},
  {id:3,cat:0,d:1,q:"Which red grape variety is the most widely planted in the world?",o:["Merlot","Pinot Noir","Cabernet Sauvignon","Tempranillo"],a:2,exp:"Cabernet Sauvignon is the most widely planted red grape variety globally, found in virtually every major wine-producing country."},
  {id:4,cat:0,d:2,q:"Gewürztraminer is characterised by which distinctive aroma?",o:["Blackcurrant and cedar","Lychee and rose petal","Citrus and mineral","Green apple and pear"],a:1,exp:"Gewürztraminer is highly aromatic with distinctive lychee, rose petal, and Turkish delight aromas. It typically has low acidity and deep golden colour."},
  {id:5,cat:0,d:1,q:"Which grape variety is used to make Barolo and Barbaresco?",o:["Sangiovese","Barbera","Nebbiolo","Dolcetto"],a:2,exp:"Nebbiolo is the grape behind Barolo and Barbaresco, both from Piedmont, Italy. It produces wines with high tannin, high acidity, and aromas of tar and roses."},
  {id:6,cat:0,d:1,q:"Riesling is most associated with which country?",o:["France","Italy","Germany","Spain"],a:2,exp:"While Riesling is grown in Alsace (France) and elsewhere, Germany is its spiritual home, particularly the Mosel, Rheingau, and Pfalz regions."},
  {id:7,cat:0,d:2,q:"Tempranillo is the principal grape of which Spanish wine region?",o:["Priorat","Rías Baixas","Rioja","Sherry"],a:2,exp:"Tempranillo is the star grape of Rioja (and Ribera del Duero). The name comes from 'temprano' (early), as it ripens earlier than most Spanish red grapes."},
  {id:8,cat:0,d:1,q:"Which white grape variety is used in the production of Sancerre?",o:["Chardonnay","Chenin Blanc","Sauvignon Blanc","Viognier"],a:2,exp:"Sancerre, in the Loire Valley, is made exclusively from Sauvignon Blanc. Pouilly-Fumé, just across the river, also uses Sauvignon Blanc."},
  {id:9,cat:0,d:2,q:"Sangiovese is the primary grape in which Italian wine?",o:["Barolo","Chianti","Soave","Amarone"],a:1,exp:"Sangiovese is the principal grape of Chianti and Brunello di Montalcino, both from Tuscany. It gives wines with cherry fruit, high acidity, and firm tannins."},
  {id:10,cat:0,d:1,q:"Syrah and Shiraz are:",o:["Different grape varieties","The same variety — Syrah in France, Shiraz in Australia","Syrah is a clone of Shiraz","Blending partners only"],a:1,exp:"Syrah and Shiraz are the same grape variety. 'Syrah' is used in France and most of Europe; 'Shiraz' is used in Australia and South Africa."},
  {id:11,cat:0,d:2,q:"Which grape is known for making deeply coloured wines in Cahors, France, and is the signature grape of Argentina?",o:["Merlot","Malbec","Carménère","Tannat"],a:1,exp:"Malbec originated in Cahors (where it's called Cot) but found its greatest success in Mendoza, Argentina, producing rich, plummy, deeply coloured wines."},
  {id:12,cat:0,d:2,q:"Pinot Grigio and Pinot Gris are the same grape. Which style is typically richer and more full-bodied?",o:["Italian Pinot Grigio","Alsatian Pinot Gris","They are always the same style","New Zealand Pinot Gris"],a:1,exp:"Alsatian Pinot Gris tends to be richer, fuller-bodied, and more aromatic. Italian Pinot Grigio is typically lighter, crisper, and more neutral."},
  {id:13,cat:0,d:1,q:"Which grape variety is most associated with New Zealand's Marlborough region?",o:["Chardonnay","Pinot Noir","Sauvignon Blanc","Riesling"],a:2,exp:"Marlborough Sauvignon Blanc put New Zealand on the wine map, known for its intense passion fruit, gooseberry, and herbaceous character."},
  {id:14,cat:0,d:2,q:"Viognier is known for which typical aromatic character?",o:["Green herbs and mineral","Peach, apricot, and floral notes","Citrus and flinty","Tropical and oaky"],a:1,exp:"Viognier produces aromatic whites with peach, apricot, and floral (blossom) aromas. It's the sole grape of Condrieu in the Northern Rhône."},
  {id:15,cat:0,d:1,q:"Chenin Blanc is a key grape variety of which wine region?",o:["Burgundy","Loire Valley","Bordeaux","Rhône Valley"],a:1,exp:"Chenin Blanc is the star of the Loire Valley (Vouvray, Savennières, etc.) and also hugely important in South Africa, where it's called Steen."},
  {id:16,cat:0,d:2,q:"Gamay is the grape behind which famous wine?",o:["Côtes du Rhône","Beaujolais","Sancerre","Châteauneuf-du-Pape"],a:1,exp:"Gamay is the sole red grape of Beaujolais. It produces light, fruity, low-tannin wines, especially in the carbonic maceration style of Beaujolais Nouveau."},
  {id:17,cat:0,d:2,q:"Which grape variety is most associated with Sémillon and is often blended with Sauvignon Blanc in Bordeaux?",o:["Muscadelle","Sémillon (trick — it IS Sémillon)","Colombard","Ugni Blanc"],a:1,exp:"Sémillon is the key blending partner with Sauvignon Blanc in white Bordeaux. It's also crucial for Sauternes, where it's susceptible to noble rot (botrytis)."},
  {id:18,cat:0,d:1,q:"Grenache (Garnacha) is a key grape in which region?",o:["Burgundy","Southern Rhône / Châteauneuf-du-Pape","Mosel","Piedmont"],a:1,exp:"Grenache is the dominant grape of the Southern Rhône (Châteauneuf-du-Pape) and is widely planted across Spain (as Garnacha), producing warm, fruity wines."},
  {id:19,cat:0,d:2,q:"Muscat is distinctive because it is one of the few grapes that:",o:["Has no colour","Actually tastes and smells grapey","Cannot make sweet wine","Only grows in France"],a:1,exp:"Muscat is unique among wine grapes because its wines actually smell and taste of grapes. It comes in many forms, from dry Muscadet to sweet Muscat de Beaumes-de-Venise."},
  {id:20,cat:0,d:2,q:"Zinfandel is genetically identical to which European grape?",o:["Sangiovese","Primitivo","Negroamaro","Montepulciano"],a:1,exp:"Zinfandel (California) and Primitivo (Puglia, Italy) are genetically identical. The grape originally comes from Croatia (Crljenak Kaštelanski)."},
  {id:21,cat:0,d:1,q:"The classic Bordeaux red blend typically features which two main grapes?",o:["Syrah and Grenache","Cabernet Sauvignon and Merlot","Pinot Noir and Gamay","Tempranillo and Garnacha"],a:1,exp:"Bordeaux reds are based on Cabernet Sauvignon (dominant on the Left Bank) and Merlot (dominant on the Right Bank), often with Cabernet Franc, Petit Verdot, and Malbec."},
  {id:22,cat:0,d:2,q:"Which of these is a characteristic of Cabernet Sauvignon?",o:["Low tannin, light body","High tannin, blackcurrant, cedar when aged","Floral aromas, silky texture","Low acidity, sweet fruit"],a:1,exp:"Cabernet Sauvignon is characterised by high tannin, full body, blackcurrant (cassis) fruit, and develops cedar/cigar box notes with oak ageing."},
  {id:23,cat:0,d:1,q:"Merlot is generally described as being ______ compared to Cabernet Sauvignon.",o:["More tannic and acidic","Softer and more approachable","More aromatic and floral","Lighter in colour"],a:1,exp:"Merlot is typically softer, rounder, and more approachable than Cabernet Sauvignon, with plum and red fruit flavours and moderate tannins."},
  {id:24,cat:0,d:2,q:"Albariño is the signature white grape of which region?",o:["Rioja, Spain","Rías Baixas, Spain","Douro, Portugal","Provence, France"],a:1,exp:"Albariño is the star grape of Rías Baixas in Galicia, northwest Spain. It produces crisp, aromatic whites with peach and citrus flavours."},
  {id:25,cat:0,d:2,q:"Pinot Noir typically produces wines that are:",o:["Deep in colour with high tannins","Pale to medium in colour with red fruit aromas","Very dark with blackberry flavours","Pale with green, herbaceous notes"],a:1,exp:"Pinot Noir is typically pale to medium ruby, with red fruit (cherry, strawberry, raspberry), light to medium tannins, and high acidity."},
  {id:26,cat:1,d:1,q:"Which of the following is a Left Bank Bordeaux appellation?",o:["Saint-Émilion","Pomerol","Médoc","Fronsac"],a:2,exp:"The Médoc (including Margaux, Pauillac, Saint-Julien, Saint-Estèphe) is on the Left Bank. Saint-Émilion and Pomerol are Right Bank."},
  {id:27,cat:1,d:1,q:"The Barossa Valley is a famous wine region in which country?",o:["New Zealand","South Africa","Chile","Australia"],a:3,exp:"The Barossa Valley is in South Australia, famous for powerful, rich Shiraz from some of the oldest vines in the world."},
  {id:28,cat:1,d:2,q:"Chablis is located in which part of France?",o:["Southern Rhône","Northern part of Burgundy","Loire Valley","Alsace"],a:1,exp:"Chablis is the northernmost district of Burgundy. Its Chardonnay is known for being lean, mineral, and unoaked compared to southern Burgundy."},
  {id:29,cat:1,d:1,q:"Mendoza is the most important wine region of which country?",o:["Chile","Argentina","Uruguay","Brazil"],a:1,exp:"Mendoza produces about 70% of Argentina's wine. It sits at high altitude in the foothills of the Andes, ideal for Malbec."},
  {id:30,cat:1,d:2,q:"The Douro Valley is best known for producing which type of wine?",o:["Cava","Sherry","Port","Madeira"],a:2,exp:"The Douro Valley in northern Portugal is where Port is produced. Grapes are grown on dramatic terraced hillsides and the wine is fortified in the Douro."},
  {id:31,cat:1,d:1,q:"Napa Valley is located in which US state?",o:["Oregon","Washington","California","New York"],a:2,exp:"Napa Valley in California is one of the most prestigious wine regions in the New World, particularly famous for Cabernet Sauvignon."},
  {id:32,cat:1,d:2,q:"Which region is known for Grüner Veltliner?",o:["Germany","Austria","Switzerland","Hungary"],a:1,exp:"Grüner Veltliner is Austria's signature white grape, producing fresh, peppery, citrusy wines. It accounts for about a third of Austrian vineyards."},
  {id:33,cat:1,d:1,q:"Champagne can only come from:",o:["Anywhere in France","The Champagne region in northeast France","Any EU country using traditional method","Burgundy and Champagne"],a:1,exp:"Champagne is a protected name (AOC/PDO) and can only come from the Champagne region in northeast France. Similar wines elsewhere must use different names."},
  {id:34,cat:1,d:2,q:"The Mosel region in Germany is famous for which style of Riesling?",o:["Full-bodied and oaked","Light, high-acid, often off-dry with slate minerality","Rich and tropical","Always bone-dry"],a:1,exp:"Mosel Rieslings are typically light-bodied, high in acidity, with slate minerality, and range from dry to sweet. The steep slopes create ideal growing conditions."},
  {id:35,cat:1,d:2,q:"Stellenbosch is a premium wine region in which country?",o:["Australia","Chile","New Zealand","South Africa"],a:3,exp:"Stellenbosch is South Africa's most prestigious wine region, known for Cabernet Sauvignon, Bordeaux blends, and Chenin Blanc."},
  {id:36,cat:1,d:1,q:"The Northern Rhône is best known for which red grape?",o:["Grenache","Mourvèdre","Syrah","Carignan"],a:2,exp:"Syrah is the sole red grape of the Northern Rhône appellations (Hermitage, Côte-Rôtie, Cornas, Saint-Joseph, Crozes-Hermitage)."},
  {id:37,cat:1,d:2,q:"Tokaj (Tokaji) is a famous sweet wine region in which country?",o:["Austria","Hungary","Romania","Czech Republic"],a:1,exp:"Tokaj in Hungary is famous for Tokaji Aszú, one of the world's great sweet wines, made from botrytised Furmint grapes."},
  {id:38,cat:1,d:1,q:"Prosecco comes from which country?",o:["Spain","France","Germany","Italy"],a:3,exp:"Prosecco comes from the Veneto and Friuli Venezia Giulia regions of northeastern Italy. It's made from the Glera grape using the tank method."},
  {id:39,cat:1,d:2,q:"Oregon's Willamette Valley is most celebrated for which grape?",o:["Cabernet Sauvignon","Merlot","Pinot Noir","Zinfandel"],a:2,exp:"The Willamette Valley has a cool climate similar to Burgundy, making it ideal for Pinot Noir."},
  {id:40,cat:1,d:2,q:"Châteauneuf-du-Pape is in which wine region?",o:["Northern Rhône","Southern Rhône","Languedoc","Provence"],a:1,exp:"Châteauneuf-du-Pape is the most prestigious appellation of the Southern Rhône. Up to 13 grape varieties are permitted, with Grenache dominant."},
  {id:41,cat:1,d:1,q:"Which country's wine regions include Hawke's Bay and Central Otago?",o:["Australia","Chile","South Africa","New Zealand"],a:3,exp:"Hawke's Bay (known for Bordeaux-style reds) and Central Otago (known for Pinot Noir) are both important wine regions in New Zealand."},
  {id:42,cat:1,d:2,q:"Alsace is located on the border between France and:",o:["Belgium","Switzerland","Germany","Luxembourg"],a:2,exp:"Alsace sits on France's northeast border with Germany. Its wines reflect both cultures, using Germanic grape varieties but French winemaking."},
  {id:43,cat:1,d:1,q:"Which is NOT a major wine region of Italy?",o:["Tuscany","Piedmont","Veneto","Champagne"],a:3,exp:"Champagne is in France. Tuscany (Chianti, Brunello), Piedmont (Barolo, Barbaresco), and Veneto (Valpolicella, Prosecco) are all major Italian regions."},
  {id:44,cat:1,d:2,q:"Maipo Valley, famous for Cabernet Sauvignon, is in which country?",o:["Argentina","Chile","Uruguay","Peru"],a:1,exp:"Maipo Valley is Chile's most famous wine region, located near Santiago. It's particularly known for premium Cabernet Sauvignon."},
  {id:45,cat:1,d:2,q:"What makes the Rheingau special for Riesling production?",o:["Very warm climate","South-facing slopes along the Rhine providing ideal sun exposure","Volcanic soil only","Extremely high altitude"],a:1,exp:"The Rheingau benefits from a unique stretch where the Rhine flows east-west, creating south-facing slopes that give Riesling optimal sun exposure."},
  {id:46,cat:1,d:1,q:"The Central Valley is the largest wine-producing area of which country?",o:["Spain","Australia","Chile","South Africa"],a:2,exp:"Chile's Central Valley is a vast wine-producing area benefiting from Andes meltwater irrigation."},
  {id:47,cat:1,d:2,q:"Côte de Nuits and Côte de Beaune together form which famous area?",o:["Côte Chalonnaise","Côte d'Or","Mâconnais","Chablis"],a:1,exp:"The Côte d'Or ('Golden Slope') is the heart of Burgundy. Côte de Nuits is famous for reds, Côte de Beaune for whites."},
  {id:48,cat:1,d:2,q:"Margaret River is a premium wine region in which part of Australia?",o:["South Australia","Victoria","Western Australia","New South Wales"],a:2,exp:"Margaret River in Western Australia is known for high-quality Cabernet Sauvignon and Chardonnay."},
  {id:49,cat:1,d:1,q:"Ribera del Duero is in which country?",o:["Portugal","Spain","Italy","Argentina"],a:1,exp:"Ribera del Duero is a prestigious Spanish region on the Duero river. Tempranillo (called Tinto Fino here) is the main grape."},
  {id:50,cat:1,d:2,q:"The Clare Valley and Eden Valley in Australia are best known for which grape?",o:["Shiraz","Chardonnay","Riesling","Cabernet Sauvignon"],a:2,exp:"Clare Valley and Eden Valley in South Australia are renowned for producing exceptional dry Rieslings."},
  {id:51,cat:2,d:1,q:"Alcoholic fermentation converts sugar into:",o:["Water and carbon dioxide","Alcohol and carbon dioxide","Alcohol and oxygen","Tannin and acid"],a:1,exp:"Yeast converts grape sugar into alcohol (ethanol) and carbon dioxide (CO₂). This is the fundamental process in winemaking."},
  {id:52,cat:2,d:2,q:"What is malolactic fermentation (MLF)?",o:["A second alcoholic fermentation","Conversion of malic acid to lactic acid","Adding acid to wine","Fermenting on the lees"],a:1,exp:"MLF converts sharp malic acid (think green apple) to softer lactic acid (think dairy). It gives wines a creamier, rounder mouthfeel."},
  {id:53,cat:2,d:1,q:"What does 'ageing on lees' mean?",o:["Ageing in new oak barrels","Leaving wine in contact with dead yeast cells","Adding sulphur dioxide","Ageing in stainless steel only"],a:1,exp:"Lees are dead yeast cells that settle after fermentation. Ageing on lees adds richness, complexity, and a bready/biscuity character."},
  {id:54,cat:2,d:1,q:"Oak ageing can impart which flavours to wine?",o:["Green apple and citrus","Vanilla, toast, and spice","Petrol and mineral","Gooseberry and grass"],a:1,exp:"Oak barrels can add vanilla, toast, clove, coconut, and smoky characters. New oak has stronger flavour than old oak."},
  {id:55,cat:2,d:2,q:"What is carbonic maceration?",o:["Fermenting grapes whole in a CO₂-rich environment","Adding carbon dioxide to wine","A type of cold fermentation","Removing carbon dioxide from wine"],a:0,exp:"Carbonic maceration involves fermenting whole, uncrushed grapes in a CO₂-rich environment. It produces fruity, low-tannin wines."},
  {id:56,cat:2,d:1,q:"The colour of red wine comes from:",o:["The juice of red grapes","Contact with grape skins during fermentation","Adding natural colourants","The type of yeast used"],a:1,exp:"Red grape juice is actually clear. The colour comes from pigments (anthocyanins) in the grape skins during maceration/fermentation."},
  {id:57,cat:2,d:2,q:"What is the purpose of fining in winemaking?",o:["To add flavour","To increase alcohol","To clarify and stabilise wine by removing particles","To add colour"],a:2,exp:"Fining agents (egg white, bentonite, casein) are added to attract and remove unwanted particles, making wine clearer and more stable."},
  {id:58,cat:2,d:1,q:"What role does sulphur dioxide (SO₂) play in winemaking?",o:["Adds sweetness","Acts as a preservative and antioxidant","Increases alcohol level","Creates bubbles"],a:1,exp:"SO₂ is used as a preservative — it prevents oxidation and inhibits unwanted microbial activity."},
  {id:59,cat:2,d:2,q:"What is chaptalisation?",o:["Adding acid to grape must","Adding sugar to grape must before fermentation to increase alcohol","Adding tannin to wine","Blending wines from different vintages"],a:1,exp:"Chaptalisation is adding sugar before fermentation to increase potential alcohol (not sweetness). Practised in cooler regions but banned in many warm regions."},
  {id:60,cat:2,d:1,q:"A wine labelled 'unoaked' has been fermented and aged in:",o:["New French oak barrels","American oak barrels","Stainless steel or concrete (inert vessels)","Old oak barrels only"],a:2,exp:"Unoaked wines are fermented and aged in inert vessels (stainless steel, concrete) to preserve fresh fruit character."},
  {id:61,cat:2,d:2,q:"What is botrytis cinerea (noble rot)?",o:["A yeast used in fermentation","A fungus that concentrates sugars in grapes for sweet wines","A bacteria that causes MLF","A vine disease that kills grapes"],a:1,exp:"Noble rot (Botrytis cinerea) shrivels grapes, concentrating sugars, acids, and flavours. Essential for Sauternes and Tokaji Aszú."},
  {id:62,cat:2,d:2,q:"In the production of rosé wine, the most common method is:",o:["Blending red and white wine","Short skin contact with red grapes","Using pink-skinned grapes only","Adding food colouring"],a:1,exp:"Most rosé is made by short maceration — limited skin contact with red grape skins gives a pink colour."},
  {id:63,cat:2,d:1,q:"What is the effect of cooler climate on grape ripening?",o:["Higher sugar, lower acid","Lower sugar, higher acid","No effect on sugar or acid","Higher sugar, higher acid"],a:1,exp:"In cooler climates, grapes retain more acidity and develop less sugar, leading to lower alcohol, higher acidity, and more subtle fruit."},
  {id:64,cat:2,d:2,q:"What does 'battonage' mean?",o:["Stirring the lees during ageing","Pressing the grapes","Filtering the wine","Adding oak chips"],a:0,exp:"Bâtonnage is stirring the lees (dead yeast) during ageing, adding richness, texture, and complexity."},
  {id:65,cat:2,d:1,q:"Which vessel preserves the fresh fruit character of a wine best?",o:["New French oak barrel","New American oak barrel","Stainless steel tank","Old oak barrel"],a:2,exp:"Stainless steel is inert — it imparts no flavour and preserves fresh, primary fruit characters."},
  {id:66,cat:2,d:2,q:"What is the typical effect of new oak vs old oak on wine?",o:["New oak adds more flavour; old oak adds less","Old oak adds more flavour than new oak","Both add the same flavour","Neither adds any flavour"],a:0,exp:"New oak imparts strong vanilla, toast, spice, and tannin. After 3-4 uses, old oak becomes largely neutral."},
  {id:67,cat:2,d:2,q:"What is the process of 'riddling' (remuage) associated with?",o:["Port production","Traditional method sparkling wine","Sherry production","Natural wine production"],a:1,exp:"Riddling involves gradually tilting and rotating bottles to collect sediment in the neck before disgorgement."},
  {id:68,cat:2,d:1,q:"Tannins in red wine primarily come from:",o:["The juice only","Grape skins, seeds, and stems (and sometimes oak)","The fermentation yeast","Added sulphites"],a:1,exp:"Tannins come from grape skins, seeds, and stems during maceration. Oak barrels also contribute tannin."},
  {id:69,cat:2,d:2,q:"What is the difference between free-run juice and press juice?",o:["Free-run is sweeter","Free-run flows naturally; press juice is extracted under pressure and is more tannic","There is no difference","Press juice is lighter"],a:1,exp:"Free-run juice flows naturally — lighter and finer. Press juice is extracted by pressing and contains more tannin and colour."},
  {id:70,cat:2,d:1,q:"What does 'vintage' or 'vintage year' refer to on a wine label?",o:["The year the wine was bottled","The year the grapes were harvested","The year the wine was released","The age of the vines"],a:1,exp:"The vintage year refers to the year the grapes were harvested. Vintage variation is caused by different weather conditions each year."},
  {id:71,cat:3,d:1,q:"On a French wine label, what does 'Appellation d'Origine Contrôlée' (AOC/AOP) indicate?",o:["The wine is organic","The wine meets strict regional and quality regulations","The wine is from a single vineyard","The grape variety used"],a:1,exp:"AOC/AOP guarantees the wine is from a specific region and follows strict rules on grape varieties, yields, and production methods."},
  {id:72,cat:3,d:2,q:"What does 'Crianza' mean on a Spanish wine label?",o:["The wine is unaged","The wine has been aged for a minimum period, including time in oak","The wine is sweet","The wine is a single vineyard"],a:1,exp:"Crianza indicates minimum ageing: for reds, at least 2 years total with minimum 6 months in oak."},
  {id:73,cat:3,d:1,q:"A wine labelled 'dry' means:",o:["It has a high tannin content","It contains little or no residual sugar","It has high acidity","It was aged in oak"],a:1,exp:"A dry wine has little or no residual sugar (generally under 4 g/l). Tannin creates a 'drying' sensation but is separate from sweetness."},
  {id:74,cat:3,d:2,q:"What does 'Riserva' indicate on an Italian wine label?",o:["The wine is organic","The wine has undergone longer ageing than the standard version","The grapes are from a single vineyard","The wine is sweet"],a:1,exp:"Riserva indicates the wine has been aged for a longer period than the regular version."},
  {id:75,cat:3,d:1,q:"A 'varietal' wine label (e.g. 'Chardonnay') tells you:",o:["The region of production","The dominant grape variety used","The vintage year","The producer name"],a:1,exp:"Varietal labelling names the grape variety. In most New World countries, at least 75-85% must be from the named variety."},
  {id:76,cat:3,d:2,q:"What does 'Brut' mean on a sparkling wine label?",o:["Sweet","Dry (very low residual sugar)","Semi-sweet","Extra sweet"],a:1,exp:"Brut means dry — less than 12 g/l residual sugar."},
  {id:77,cat:3,d:2,q:"Confusingly, 'Extra Dry' on a Prosecco label means:",o:["Bone dry","Very slightly sweet (off-dry)","Medium sweet","The same as Brut"],a:1,exp:"Extra Dry (12-17 g/l sugar) is actually slightly sweeter than Brut (<12 g/l). A common WSET exam question!"},
  {id:78,cat:3,d:1,q:"The term 'Old World' in wine refers to:",o:["Any wine over 10 years old","Wine-producing countries with long histories (Europe, Middle East)","Only French wine","Wines made with traditional methods only"],a:1,exp:"Old World refers to traditional wine-producing regions in Europe and the Middle East. New World includes the Americas, Australasia, South Africa."},
  {id:79,cat:3,d:2,q:"What does 'Grand Cru' mean in Burgundy?",o:["A large estate","The highest vineyard classification","A type of barrel","A cooperative winery"],a:1,exp:"In Burgundy, Grand Cru is the highest vineyard classification, above Premier Cru and Village level."},
  {id:80,cat:3,d:2,q:"What does 'DOCG' indicate?",o:["A basic table wine","Italy's highest quality classification for wine","A geographic indication only","The wine is organic"],a:1,exp:"DOCG is Italy's highest wine quality classification. Wines must meet stricter rules than DOC, including tasting panel approval."},
  {id:81,cat:3,d:1,q:"A wine described as having 'high acidity' will taste:",o:["Bitter and astringent","Fresh, crisp, mouth-watering","Sweet and rich","Flat and dull"],a:1,exp:"High acidity makes wine taste fresh, crisp, and makes your mouth water."},
  {id:82,cat:3,d:2,q:"What is a 'single varietal' wine vs. a 'blend'?",o:["Single varietal uses one grape; blend combines multiple varieties","They are the same thing","Single varietal means single vineyard","Blend means blended vintages"],a:0,exp:"A single varietal wine is made predominantly from one grape variety. A blend combines two or more varieties."},
  {id:83,cat:3,d:1,q:"The alcohol percentage on a wine label is expressed as:",o:["Grams per litre","Percentage of alcohol by volume (ABV)","Proof","Parts per million"],a:1,exp:"Wine alcohol content is expressed as ABV. Table wines typically range from 8% to 15% ABV."},
  {id:84,cat:3,d:2,q:"German Prädikat levels (Kabinett, Spätlese, Auslese, etc.) are based on:",o:["Vineyard quality","Grape ripeness at harvest","Ageing time","Alcohol content"],a:1,exp:"The German Prädikat system classifies wines by grape ripeness (sugar level) at harvest."},
  {id:85,cat:3,d:2,q:"What does 'Mis en bouteille au château' mean on a French label?",o:["Blended from multiple producers","Bottled at the estate/château","Made from organic grapes","Aged in new oak"],a:1,exp:"This means 'bottled at the château/estate', indicating estate-produced wine."},
  {id:86,cat:4,d:1,q:"The Traditional Method (méthode traditionnelle) involves:",o:["Adding CO₂ artificially","Second fermentation in the bottle","Second fermentation in a large tank","Fermenting in open barrels"],a:1,exp:"The Traditional Method involves a second fermentation inside the bottle, creating fine, persistent bubbles."},
  {id:87,cat:4,d:2,q:"The Tank Method (Charmat/Martinotti) is used for which wine?",o:["Champagne","Cava","Prosecco","Crémant"],a:2,exp:"Prosecco uses the Tank Method — second fermentation in large pressurised tanks, preserving fresh, fruity character."},
  {id:88,cat:4,d:1,q:"The three main grape varieties used in Champagne are:",o:["Chardonnay, Chenin Blanc, Pinot Blanc","Chardonnay, Pinot Noir, Pinot Meunier","Riesling, Pinot Gris, Pinot Blanc","Sauvignon Blanc, Sémillon, Muscadelle"],a:1,exp:"Champagne uses Chardonnay (finesse), Pinot Noir (body/structure), and Pinot Meunier (fruitiness)."},
  {id:89,cat:4,d:2,q:"What does 'NV' (Non-Vintage) mean on a Champagne label?",o:["Not valuable","A blend of wines from multiple years","New vineyard","Not verified"],a:1,exp:"NV Champagne is blended from wines of multiple vintages to maintain a consistent house style."},
  {id:90,cat:4,d:1,q:"What makes a wine 'fortified'?",o:["Higher acidity","Addition of grape spirit (brandy) to increase alcohol","Double fermentation","Extra-long ageing"],a:1,exp:"Fortified wines have grape spirit added, raising the alcohol to 15-22%."},
  {id:91,cat:4,d:2,q:"In Port production, when is the grape spirit added?",o:["Before fermentation","During fermentation (to stop it and retain sweetness)","After fermentation is complete","During bottling"],a:1,exp:"Port is fortified DURING fermentation. The spirit kills the yeast, stopping fermentation and leaving residual sugar."},
  {id:92,cat:4,d:2,q:"Fino and Manzanilla are styles of which fortified wine?",o:["Port","Madeira","Sherry","Marsala"],a:2,exp:"Fino and Manzanilla are dry, light styles of Sherry aged under a layer of flor yeast."},
  {id:93,cat:4,d:2,q:"What is 'flor' in Sherry production?",o:["A grape variety","A layer of yeast that forms on the wine's surface","A type of barrel","A blending technique"],a:1,exp:"Flor is a film of yeast on the surface of Fino and Manzanilla Sherry, protecting from oxidation and adding nutty, yeasty flavours."},
  {id:94,cat:4,d:1,q:"What is the difference between Tawny Port and Ruby Port?",o:["Tawny is aged in barrel (oxidative); Ruby is aged in bottle (reductive)","They are the same","Ruby is aged longer","Tawny is always sweet, Ruby is dry"],a:0,exp:"Tawny Port is aged in small barrels (becoming amber with nutty flavours). Ruby Port is aged in large vessels, retaining deep colour and fresh fruit."},
  {id:95,cat:4,d:2,q:"Cava is Spain's traditional method sparkling wine. Which grapes are most commonly used?",o:["Chardonnay, Pinot Noir, Pinot Meunier","Macabeo, Parellada, Xarel-lo","Tempranillo, Garnacha, Graciano","Albariño, Verdejo, Godello"],a:1,exp:"Cava is typically made from indigenous Spanish grapes: Macabeo, Parellada, and Xarel-lo."},
  {id:96,cat:4,d:2,q:"Oloroso Sherry is different from Fino because:",o:["It's made from different grapes","It ages without flor, developing oxidative character","It's always sweet","It's lower in alcohol"],a:1,exp:"Oloroso is fortified to higher alcohol so flor cannot develop. It ages oxidatively, becoming dark, rich, and nutty."},
  {id:97,cat:4,d:1,q:"Blanc de Blancs Champagne is made from:",o:["Only red grapes","Only Chardonnay (white grapes)","A mix of red and white grapes","Only Pinot Meunier"],a:1,exp:"Blanc de Blancs means 'white from whites' — made exclusively from Chardonnay."},
  {id:98,cat:4,d:2,q:"What is Sauternes?",o:["A dry red Bordeaux wine","A sweet white Bordeaux wine made from botrytised grapes","A sparkling wine from the Loire","A rosé from Provence"],a:1,exp:"Sauternes is a luscious sweet white wine from Bordeaux, made primarily from botrytised Sémillon."},
  {id:99,cat:4,d:1,q:"Asti and Moscato d'Asti are sparkling wines from Italy made with which grape?",o:["Glera","Muscat (Moscato)","Trebbiano","Cortese"],a:1,exp:"Asti and Moscato d'Asti are made from Muscat Blanc à Petits Grains in Piedmont."},
  {id:100,cat:4,d:2,q:"LBV (Late Bottled Vintage) Port is:",o:["Aged 20 years in barrel","A single vintage Port aged 4-6 years in barrel before bottling","The same as Vintage Port","Always white Port"],a:1,exp:"LBV Port is from a single vintage, aged 4-6 years in barrel. A ready-to-drink style."},
  {id:101,cat:5,d:1,q:"The general principle of food and wine pairing is to:",o:["Always drink red wine with food","Match the weight/intensity of the food with the wine","Only pair wine with cheese","Always choose the most expensive wine"],a:1,exp:"The key principle is matching weight and intensity."},
  {id:102,cat:5,d:1,q:"Salty foods generally make wine taste:",o:["More bitter and tannic","Softer, less bitter, and more fruity","More acidic","More alcoholic"],a:1,exp:"Salt reduces the perception of bitterness and tannin in wine, making it taste softer and more fruity."},
  {id:103,cat:5,d:2,q:"Why does Sancerre (Sauvignon Blanc) pair well with goat's cheese?",o:["Both are expensive","The wine's acidity cuts through the cheese's richness; it's a regional pairing","The wine is sweet","The cheese is tannic"],a:1,exp:"Sancerre's high acidity cuts through the creamy richness of goat's cheese. This is also a classic Loire Valley regional pairing."},
  {id:104,cat:5,d:1,q:"Sweet food paired with a dry wine will make the wine taste:",o:["Sweeter","More bitter, acidic, and thin","No change","More fruity"],a:1,exp:"Sweet food makes dry wine taste harsh — more bitter, acidic, and thin. The wine should be at least as sweet as the food."},
  {id:105,cat:5,d:2,q:"Which wine would best pair with a rich, creamy pasta dish?",o:["Light, acidic Riesling","Oaked Chardonnay with good body","Tannic young Barolo","Sweet Moscato d'Asti"],a:1,exp:"A rich, oaked Chardonnay matches the weight and creaminess of the dish."},
  {id:106,cat:5,d:1,q:"High-acid wines pair well with which type of food?",o:["Very sweet desserts","Fatty, rich, or oily foods","Very spicy food","Bitter vegetables"],a:1,exp:"Acidity in wine acts like a squeeze of lemon — it cuts through fat and richness, refreshing the palate."},
  {id:107,cat:5,d:2,q:"Umami-rich foods (like aged parmesan) tend to make wine taste:",o:["Sweeter and fruitier","More bitter and astringent","Lighter and more refreshing","More aromatic"],a:1,exp:"Umami increases the perception of bitterness, astringency, and acidity in wine while decreasing body and fruitiness."},
  {id:108,cat:5,d:1,q:"Which is a classic pairing for Stilton blue cheese?",o:["Dry Sauvignon Blanc","Port or Sauternes","Light Pinot Grigio","Dry Fino Sherry"],a:1,exp:"The sweetness of Port or Sauternes balances the salt and pungency of blue cheese."},
  {id:109,cat:5,d:2,q:"Why should highly tannic wines generally be paired with protein-rich foods?",o:["Protein has no effect on tannin","Protein binds with tannin, softening the wine's astringency","Protein makes tannin stronger","It's just tradition"],a:1,exp:"Protein molecules bind with tannin, reducing the drying sensation."},
  {id:110,cat:5,d:1,q:"Very spicy (chilli-hot) food pairs best with wines that are:",o:["High in alcohol and tannin","Low in alcohol, slightly sweet, and fruity","Highly tannic and dry","Heavily oaked"],a:1,exp:"Chilli heat is amplified by alcohol and tannin. Off-dry, lower-alcohol wines cool the palate."},
  {id:111,cat:5,d:2,q:"'What grows together goes together' is a pairing principle meaning:",o:["All wines taste the same with local food","Regional wines tend to pair well with regional cuisine","You should only drink local wine","Wine grapes and food crops compete for nutrients"],a:1,exp:"Wines and cuisines evolved together over centuries."},
  {id:112,cat:5,d:1,q:"A dessert wine paired with food should be:",o:["Less sweet than the food","At least as sweet as the food","Always dry","Always sparkling"],a:1,exp:"The wine should be at least as sweet as (or sweeter than) the food."},
  {id:113,cat:5,d:2,q:"Which wine would pair best with grilled salmon?",o:["Heavy Australian Shiraz","Light Pinot Noir or rosé","Young tannic Cabernet","Sweet Riesling"],a:1,exp:"Salmon has medium weight. A light-to-medium red like Pinot Noir or a dry rosé matches its weight."},
  {id:114,cat:5,d:1,q:"Champagne or sparkling wine is versatile with food because of its:",o:["Low alcohol","High acidity and effervescence which cleanse the palate","Sweet flavour","Oak character"],a:1,exp:"The combination of high acidity and bubbles makes sparkling wine incredibly food-friendly."},
  {id:115,cat:5,d:2,q:"Acidic foods (like tomato sauce) pair best with wines that:",o:["Are low in acidity","Have matching or higher acidity","Are very tannic","Are high in alcohol"],a:1,exp:"Acidic foods make low-acid wines taste flat. Matching acidity keeps both balanced."},
];
